// src/pages/Employee/EmployeePage.js
import React, { useState, useEffect, useCallback } from 'react';
import {
  Plus, Search, MoreHorizontal, Edit2,
  UserX, Eye, Mail, Phone,
  ChevronLeft, ChevronRight, Copy, CheckCheck, Settings,
} from 'lucide-react';
import toast from 'react-hot-toast';
import { employeeAPI } from '../../api/services';
import { Modal, Badge, SkeletonTable, EmptyState, ConfirmDialog, InlineSpinner } from '../../components/common';

/* ── Credentials Dialog — shown to HR after creating an employee ── */
function CredentialsDialog({ data, onClose }) {
  const [copied, setCopied] = useState('');
  if (!data) return null;

  const copy = (text, field) => {
    navigator.clipboard.writeText(text).then(() => {
      setCopied(field);
      setTimeout(() => setCopied(''), 2000);
    });
  };

  const copyAll = () => {
    const text = `University HR System — Login Credentials\n\nName: ${data.name}\nEmail: ${data.email}\nPassword: ${data.password}\nLogin URL: ${window.location.origin}/login\n\nPlease log in and change your password from Settings.`;
    navigator.clipboard.writeText(text);
    setCopied('all');
    setTimeout(() => setCopied(''), 2000);
  };

  return (
    <div className="modal-backdrop">
      <div className="modal" style={{ maxWidth: 480 }}>
        <div className="modal-header">
          <div>
            <h2 className="modal-title" style={{ color: 'var(--green)' }}>
              ✅ Employee Created Successfully
            </h2>
            <p style={{ fontSize: '0.8rem', color: 'var(--text-secondary)', marginTop: 4 }}>
              Share these login credentials with <strong>{data.name}</strong>
            </p>
          </div>
        </div>

        <div className="modal-body">
          <div style={{
            padding: '10px 14px', marginBottom: 16,
            background: 'var(--amber-dim)', border: '1px solid rgba(245,158,11,0.3)',
            borderRadius: 'var(--radius-md)', fontSize: '0.82rem', color: 'var(--amber)',
          }}>
            ⚠️ Save these credentials now — the password won't be shown again.
          </div>

          <div style={{
            background: 'var(--bg-base)', border: '1px solid var(--border)',
            borderRadius: 'var(--radius-lg)', overflow: 'hidden', marginBottom: 14,
          }}>
            {[
              { label: 'Full Name',  value: data.name,                          mono: false },
              { label: 'Email',      value: data.email,                         mono: false },
              { label: 'Password',   value: data.password,                      mono: true  },
              { label: 'Login URL',  value: `${window.location.origin}/login`,  mono: false },
            ].map(({ label, value, mono }) => (
              <div key={label} style={{
                display: 'flex', alignItems: 'center', justifyContent: 'space-between',
                padding: '12px 16px', borderBottom: '1px solid var(--border-light)',
              }}>
                <div>
                  <div style={{ fontSize: '0.7rem', color: 'var(--text-muted)', textTransform: 'uppercase', letterSpacing: '0.06em', marginBottom: 2 }}>{label}</div>
                  <div style={{
                    fontSize: '0.9rem', fontWeight: 500,
                    fontFamily: mono ? 'monospace' : 'var(--font-body)',
                    color: label === 'Password' ? 'var(--gold)' : 'var(--text-primary)',
                    letterSpacing: mono ? '0.08em' : 'normal',
                  }}>{value}</div>
                </div>
                <button className="btn btn-ghost btn-sm btn-icon" onClick={() => copy(value, label)} title={`Copy ${label}`}>
                  {copied === label ? <CheckCheck size={14} style={{ color: 'var(--green)' }} /> : <Copy size={14} />}
                </button>
              </div>
            ))}
          </div>

          <button className="btn btn-secondary w-full" onClick={copyAll} style={{ justifyContent: 'center' }}>
            {copied === 'all' ? <><CheckCheck size={15} /> Copied!</> : <><Copy size={15} /> Copy All as Text</>}
          </button>
        </div>

        <div className="modal-footer">
          <button className="btn btn-primary" onClick={onClose}>Done</button>
        </div>
      </div>
    </div>
  );
}

/* ── Positions Manager Modal ── */
const DEFAULT_POSITIONS = [
  { code: 'PROF',     title: 'Professor'                },
  { code: 'ASSOC',    title: 'Associate Professor'       },
  { code: 'ASST',     title: 'Assistant Professor'       },
  { code: 'LECT',     title: 'Lecturer'                  },
  { code: 'TA',       title: 'Teaching Assistant'        },
  { code: 'HR-MGR',   title: 'HR Manager'                },
  { code: 'ADMIN',    title: 'Administrative Officer'    },
];

function PositionsManager({ open, onClose, positions, onRefresh }) {
  const [newCode,  setNewCode]  = useState('');
  const [newTitle, setNewTitle] = useState('');
  const [saving,   setSaving]   = useState(false);
  const [seeding,  setSeeding]  = useState(false);

  const create = async (code, title) => {
    await employeeAPI.createPosition({ PositionCode: code.toUpperCase(), PositionTitle: title, IsActive: true });
  };

  const handleAdd = async () => {
    if (!newCode.trim() || !newTitle.trim()) { toast.error('Both code and title are required'); return; }
    setSaving(true);
    try {
      await create(newCode.trim(), newTitle.trim());
      toast.success(`Position "${newTitle}" added`);
      setNewCode(''); setNewTitle('');
      onRefresh();
    } catch (err) { toast.error(err.response?.data?.error?.message || 'Failed to add position'); } 
    finally { setSaving(false); }
  };

  const handleSeedAll = async () => {
    setSeeding(true);
    const existingCodes = positions.map(p => (p.PositionCode || p.positionCode || '').toUpperCase());
    const toAdd = DEFAULT_POSITIONS.filter(p => !existingCodes.includes(p.code.toUpperCase()));
    if (toAdd.length === 0) { toast('All default positions already exist'); setSeeding(false); return; }
    let added = 0;
    for (const p of toAdd) {
      try { await create(p.code, p.title); added++; } catch {}
    }
    toast.success(`Added ${added} positions`);
    onRefresh();
    setSeeding(false);
  };

  return (
    <Modal open={open} onClose={onClose} title="Manage Positions" size="modal-lg">
      <div style={{ display: 'flex', gap: 8, marginBottom: 20 }}>
        <div style={{ flex: '0 0 130px' }}><label className="form-label">Code</label><input className="form-input" placeholder="e.g. PROF" value={newCode} onChange={e => setNewCode(e.target.value.toUpperCase())} /></div>
        <div style={{ flex: 1 }}><label className="form-label">Position Title</label><input className="form-input" placeholder="e.g. Professor" value={newTitle} onChange={e => setNewTitle(e.target.value)} onKeyDown={e => e.key === 'Enter' && handleAdd()} /></div>
        <div style={{ alignSelf: 'flex-end' }}><button className="btn btn-primary" onClick={handleAdd} disabled={saving}>{saving ? <InlineSpinner /> : <><Plus size={15} /> Add</>}</button></div>
      </div>
      <div style={{ maxHeight: 300, overflowY: 'auto', border: '1px solid var(--border)', borderRadius: 'var(--radius-md)' }}>
        {positions.map((p, i) => (
          <div key={i} style={{ display: 'flex', justifyContent: 'space-between', padding: '10px 14px', borderBottom: '1px solid var(--border-light)' }}>
            <span style={{ fontWeight: 500 }}>{p.PositionTitle || p.positionTitle || p.name}</span>
            <span style={{ fontSize: '0.75rem', fontFamily: 'monospace', color: 'var(--text-muted)' }}>{p.PositionCode || p.positionCode}</span>
          </div>
        ))}
      </div>
    </Modal>
  );
}

/* ── helpers ── */
const initEmployee = {
  EmployeeCode:     '',
  FirstName:        '',
  LastName:         '',
  Email:            '',
  Phone:            '',
  DepartmentID:     '',
  PositionID:       '',
  WorkLocationID:   '',
  SupervisorID:     '', // <-- ADDED SUPERVISOR HERE
  StartDate:        '',
  CurrentStatus:    'Active',
  Gender:           '',
  EmploymentType:   'Full-Time',
  DateOfBirth:      '',
  Nationality:      '',
  MaritalStatus:    'Single',
  password:         '',   
};

const generateEmpCode = () => `EMP${Date.now().toString().slice(-6)}`;

function EmployeeForm({ data, onChange, departments, positions, locations, supervisors, errors, isCreate = false }) {
  // Enhanced to support extracting Employee Names and IDs safely
  const getId = (o) => o?.EmployeeID ?? o?.employeeID ?? o?.employeeId ?? o?.DepartmentID ?? o?.departmentID ?? o?.PositionID ?? o?.positionID ?? o?.WorkLocationID ?? o?.id ?? '';
  const getName = (o) => o?.FullName ?? o?.fullName ?? o?.DepartmentName ?? o?.PositionTitle ?? o?.LocationName ?? o?.name ?? o?.title ?? `${o?.FirstName || ''} ${o?.LastName || ''}`.trim() ?? '';

  const field = (k, label, type = 'text', required = false) => (
    <div className="form-group">
      <label className={`form-label ${required ? 'required' : ''}`}>{label}</label>
      <input className="form-input" type={type} value={data[k] || ''} onChange={e => onChange(k, e.target.value)} placeholder={label} />
      {errors[k] && <div className="form-error">{errors[k]}</div>}
    </div>
  );

  const select = (k, label, opts, required = false) => (
    <div className="form-group">
      <label className={`form-label ${required ? 'required' : ''}`}>{label}</label>
      <select className="form-select" value={data[k] || ''} onChange={e => onChange(k, e.target.value)}>
        <option value="">— Select {label} —</option>
        {opts.map((o, i) => <option key={`${getId(o)}-${i}`} value={getId(o)}>{getName(o) || `Option ${i + 1}`}</option>)}
      </select>
      {errors[k] && <div className="form-error">{errors[k]}</div>}
    </div>
  );

  return (
    <>
      <div className="form-group">
        <label className="form-label required">Employee Code</label>
        <div style={{ display: 'flex', gap: 8 }}>
          <input className="form-input" type="text" value={data.EmployeeCode || ''} onChange={e => onChange('EmployeeCode', e.target.value.toUpperCase())} placeholder="e.g. EMP001" style={{ flex: 1, fontFamily: 'monospace' }} />
          <button type="button" className="btn btn-secondary btn-sm" onClick={() => onChange('EmployeeCode', generateEmpCode())}>Auto-generate</button>
        </div>
        {errors.EmployeeCode && <div className="form-error">{errors.EmployeeCode}</div>}
      </div>
      <div className="form-row">{field('FirstName', 'First Name', 'text', true)}{field('LastName',  'Last Name',  'text', true)}</div>
      <div className="form-row">{field('Email', 'Email', 'email', true)}{field('Phone', 'Phone', 'tel')}</div>
      <div className="form-row">{select('DepartmentID', 'Department', departments, true)}{select('PositionID', 'Position', positions, true)}</div>

      {/* ── NEW: Supervisor Dropdown added next to Location ── */}
      <div className="form-row">
        {select('WorkLocationID', 'Work Location', locations, true)}
        {select('SupervisorID', 'Supervisor / Manager', supervisors, false)}
      </div>

      <div className="form-row">
        {field('StartDate', 'Start Date', 'date', true)}
        {field('DateOfBirth', 'Date of Birth', 'date', true)}
      </div>
      <div className="form-row">
        {select('Gender', 'Gender', [{ id: 'Male', name: 'Male' }, { id: 'Female', name: 'Female' }, { id: 'Other', name: 'Other' }], true)}
        {select('EmploymentType', 'Employment Type', [{ id: 'Full-Time', name: 'Full-Time' }, { id: 'Part-Time', name: 'Part-Time' }, { id: 'Contract', name: 'Contract' }], true)}
      </div>
      <div className="form-row">
        {field('Nationality', 'Nationality', 'text', true)}
        {select('MaritalStatus', 'Marital Status', [{ id: 'Single', name: 'Single' }, { id: 'Married', name: 'Married' }, { id: 'Divorced', name: 'Divorced' }, { id: 'Widowed', name: 'Widowed' }])}
      </div>
      <div className="form-group">
        {select('CurrentStatus', 'Status', [{ id: 'Active', name: 'Active' }, { id: 'Inactive', name: 'Inactive' }, { id: 'OnLeave', name: 'On Leave' }], true)}
      </div>

      {isCreate && (
        <div className="form-group" style={{ marginTop: 4 }}>
          <label className="form-label required">Temporary Password</label>
          <div style={{ display: 'flex', gap: 8 }}>
            <input className="form-input" type="text" value={data.password || ''} onChange={e => onChange('password', e.target.value)} style={{ flex: 1, fontFamily: 'monospace' }} />
            <button type="button" className="btn btn-secondary btn-sm" onClick={() => onChange('password', `Uni@${Math.floor(100000 + Math.random() * 900000)}`)}>🔄 Regenerate</button>
          </div>
          {errors.password && <div className="form-error">{errors.password}</div>}
        </div>
      )}
    </>
  );
}

export default function EmployeePage() {
  const [employees, setEmployees]   = useState([]);
  const [departments, setDepartments] = useState([]);
  const [positions, setPositions]   = useState([]);
  const [locations, setLocations]   = useState([]);
  const [supervisors, setSupervisors] = useState([]); // <-- State to hold all employees for the dropdown
  const [loading, setLoading]       = useState(true);
  const [search, setSearch]         = useState('');
  const [deptFilter, setDeptFilter] = useState('');
  const [statusFilter, setStatusFilter] = useState('');
  const [page, setPage]             = useState(1);
  const [total, setTotal]           = useState(0);
  const LIMIT = 10;

  const [createModal, setCreateModal]   = useState(false);
  const [editModal, setEditModal]       = useState(null);
  const [viewModal, setViewModal]       = useState(null);
  const [deleteModal, setDeleteModal]   = useState(null);
  const [formData, setFormData]         = useState(initEmployee);
  const [formErrors, setFormErrors]     = useState({});
  const [saving, setSaving]             = useState(false);
  const [deleting, setDeleting]         = useState(false);

  const [openMenu, setOpenMenu] = useState(null);
  const [credentialsDialog, setCredentialsDialog] = useState(null);
  const [positionsModal, setPositionsModal] = useState(false);

  // Load all lookups, INCLUDING a list of employees to act as Supervisors
  useEffect(() => {
    const toArr = (resData, keys) => {
      if (!resData) return [];
      if (Array.isArray(resData)) return resData;
      // ── FIXED: Tell it to check the generic "data" folder! ──
      if (Array.isArray(resData?.data)) return resData.data; 

      for (const k of keys) if (Array.isArray(resData?.[k])) return resData[k];
      return [];
    };

    Promise.all([
      employeeAPI.getDepartments(),
      employeeAPI.getPositions(),
      employeeAPI.getWorkLocations(),
      employeeAPI.list({ limit: 500, isActive: true }) // Fetch potential supervisors
    ]).then(([d, p, l, s]) => {
      setDepartments(toArr(d.data, ['departments','department','items']));
      setPositions(toArr(p.data,   ['positions','position','items']));
      setLocations(toArr(l.data,   ['locations','workLocations','items']));

      const sData = s.data?.data || s.data;
      setSupervisors(Array.isArray(sData) ? sData : sData?.employees || []);
    }).catch(err => console.error('Lookup load failed:', err));
  }, []);

  const loadEmployees = useCallback(() => {
    setLoading(true);
    employeeAPI.list({
      search:       search       || undefined,
      departmentId: deptFilter   || undefined,
      status:       statusFilter || undefined,
      page,
      limit: LIMIT,
    })
      .then(({ data }) => {
        const list = Array.isArray(data) ? data : data?.employees || data?.data || [];
        setEmployees(list);
        setTotal(data?.total || data?.count || list.length || 0);
      })
      .catch(() => toast.error('Failed to load employees'))
      .finally(() => setLoading(false));
  }, [search, deptFilter, statusFilter, page]);

  useEffect(() => { loadEmployees(); }, [loadEmployees]);
  useEffect(() => { setPage(1); }, [search, deptFilter, statusFilter]);

  const validateForm = (isCreate = false) => {
    const e = {};
    if (!formData.EmployeeCode)   e.EmployeeCode   = 'Required';
    if (!formData.FirstName)      e.FirstName      = 'Required';
    if (!formData.LastName)       e.LastName       = 'Required';
    if (!formData.Email)          e.Email          = 'Required';
    if (!formData.DepartmentID)   e.DepartmentID   = 'Required';
    if (!formData.PositionID)     e.PositionID     = 'Required';
    if (!formData.StartDate)      e.StartDate      = 'Required';
    if (!formData.DateOfBirth)    e.DateOfBirth    = 'Required';
    if (!formData.Gender)         e.Gender         = 'Required';
    if (!formData.Nationality)    e.Nationality    = 'Required';
    if (!formData.WorkLocationID) e.WorkLocationID = 'Required';
    if (isCreate && !formData.password) e.password = 'Required';
    return e;
  };

  // Safely parses payload ensuring IDs are integers
  const buildPayload = () => {
    const p = { ...formData };
    ['DepartmentID', 'PositionID', 'WorkLocationID'].forEach(k => {
      if (p[k]) p[k] = parseInt(p[k], 10);
    });

    // Parse Supervisor if selected, otherwise remove it so DB doesn't crash
    if (p.SupervisorID) p.SupervisorID = parseInt(p.SupervisorID, 10);
    else delete p.SupervisorID; 

    return p;
  };

  const handleCreate = async () => {
    const e = validateForm(true);
    if (Object.keys(e).length) { setFormErrors(e); return; }
    setSaving(true);

    try {
      const payload = buildPayload();
      const res     = await employeeAPI.create(payload);
      const created = res.data?.data?.employee || res.data?.data || res.data;

      setCredentialsDialog({
        name: `${formData.FirstName} ${formData.LastName}`,
        email: formData.Email,
        password: formData.password,
        empId: created?.EmployeeID || created?.id,
      });

      toast.success('Employee profile created!');
      setCreateModal(false);
      loadEmployees();
    } catch (err) { toast.error(err.response?.data?.error?.message || 'Failed to create'); } 
    finally { setSaving(false); }
  };

  const handleUpdate = async () => {
    const e = validateForm(false);
    if (Object.keys(e).length) { setFormErrors(e); return; }
    setSaving(true);
    try {
      const payload = buildPayload();
      // If updating and supervisor is cleared, force it to null
      if (!payload.SupervisorID) payload.SupervisorID = null; 

      const id = editModal.EmployeeID || editModal.employeeID || editModal.id;
      await employeeAPI.update(id, payload);
      toast.success('Employee updated');
      setEditModal(null);
      loadEmployees();
    } catch (err) { toast.error(err.response?.data?.error?.message || 'Failed to update'); } 
    finally { setSaving(false); }
  };

  const handleDelete = async () => {
    setDeleting(true);
    try {
      const id = deleteModal.EmployeeID || deleteModal.employeeID || deleteModal.id;
      await employeeAPI.terminate(id, { reason: 'Terminated via HRMS' });
      toast.success('Employee terminated');
      setDeleteModal(null);
      loadEmployees();
    } catch (err) { toast.error('Failed to terminate'); } 
    finally { setDeleting(false); }
  };

  const openEdit = (emp) => {
    setFormData({
      ...initEmployee,
      FirstName:      emp.FirstName      || emp.firstName      || '',
      LastName:       emp.LastName       || emp.lastName       || '',
      Email:          emp.Email          || emp.email          || '',
      Phone:          emp.Phone          || emp.phone          || '',
      DepartmentID:   emp.DepartmentID   || emp.departmentID   || '',
      PositionID:     emp.PositionID     || emp.positionID     || '',
      WorkLocationID: emp.WorkLocationID || emp.workLocationID || '',
      SupervisorID:   emp.SupervisorID   || emp.supervisorID   || '', // Populates supervisor!
      StartDate:      emp.StartDate      || emp.startDate      || '',
      CurrentStatus:  emp.CurrentStatus  || emp.status         || 'Active',
      Gender:         emp.Gender         || '',
      EmploymentType: emp.EmploymentType || 'Full-Time',
      DateOfBirth:    emp.DateOfBirth    || '',
      Nationality:    emp.Nationality    || '',
      MaritalStatus:  emp.MaritalStatus  || 'Single',
    });
    setFormErrors({});
    setEditModal(emp);
    setOpenMenu(null);
  };

  const openCreate = () => {
    setFormData({ ...initEmployee, EmployeeCode: generateEmpCode(), password: `Uni@${Math.floor(100000 + Math.random() * 900000)}` });
    setFormErrors({});
    setCreateModal(true);
  };

  const totalPages = Math.ceil(total / LIMIT);
  const deptName  = (id) => departments.find(d => String(d.DepartmentID || d.id) === String(id))?.DepartmentName || '—';
  const posName   = (id) => positions.find(p => String(p.PositionID || p.id) === String(id))?.PositionTitle || '—';

  return (
    <>
      <div className="page-header-row">
        <div className="page-header" style={{ marginBottom: 0 }}><h1>Employees</h1><p>{total} total employees</p></div>
        <div style={{ display: 'flex', gap: 10 }}>
          <button className="btn btn-secondary" onClick={() => setPositionsModal(true)}><Settings size={15} /> Manage Positions</button>
          <button className="btn btn-primary" onClick={openCreate}><Plus size={16} /> Add Employee</button>
        </div>
      </div>

      <div className="filter-bar" style={{ marginTop: 20 }}>
        <div className="header-search" style={{ width: 260 }}><Search size={15} className="header-search-icon" /><input placeholder="Search name or email..." value={search} onChange={e => setSearch(e.target.value)} /></div>
        <select className="form-select" value={deptFilter} onChange={e => setDeptFilter(e.target.value)} style={{ width: 180 }}>
          <option value="">All Departments</option>
          {departments.map(d => <option key={d.id || d.DepartmentID} value={d.id || d.DepartmentID}>{d.DepartmentName || d.name}</option>)}
        </select>
        {['', 'Active', 'Inactive', 'OnLeave'].map(s => <button key={s} className={`filter-chip ${statusFilter === s ? 'active' : ''}`} onClick={() => setStatusFilter(s)}>{s || 'All Status'}</button>)}
      </div>

      {loading ? <SkeletonTable rows={8} /> : employees.length === 0 ? (
        <EmptyState icon={Users => <span style={{ fontSize: 40 }}>👥</span>} title="No employees found" description="Try adjusting your filters or add a new employee" />
      ) : (
        <>
          <div className="table-wrap">
            <table>
              <thead><tr><th>Employee</th><th>Department</th><th>Position</th><th>Hire Date</th><th>Status</th><th>Contact</th><th></th></tr></thead>
              <tbody>
                {employees.map((emp) => {
                  const id   = emp.EmployeeID || emp.id;
                  const name = `${emp.FirstName || ''} ${emp.LastName || ''}`.trim() || emp.FullName || '—';
                  return (
                    <tr key={id}>
                      <td>
                        <div style={{ display: 'flex', alignItems: 'center', gap: 10 }}>
                          <div className="avatar" style={{ width: 34, height: 34, fontSize: '0.8rem', borderRadius: 8 }}>{name[0]?.toUpperCase() || '?'}</div>
                          <div><div style={{ fontWeight: 500 }}>{name}</div><div style={{ fontSize: '0.75rem', color: 'var(--text-secondary)' }}>{emp.Email}</div></div>
                        </div>
                      </td>
                      <td>{deptName(emp.DepartmentID)}</td>
                      <td>{posName(emp.PositionID) || emp.Position?.PositionTitle || '—'}</td>
                      <td>{emp.StartDate ? new Date(emp.StartDate).toLocaleDateString() : '—'}</td>
                      <td><Badge status={emp.CurrentStatus || 'Active'}>{emp.CurrentStatus || 'Active'}</Badge></td>
                      <td>
                        <div style={{ display: 'flex', gap: 6 }}>
                          {emp.Email && <a href={`mailto:${emp.Email}`} className="btn btn-ghost btn-icon btn-sm"><Mail size={14} /></a>}
                          {emp.Phone && <a href={`tel:${emp.Phone}`} className="btn btn-ghost btn-icon btn-sm"><Phone size={14} /></a>}
                        </div>
                      </td>
                      <td style={{ position: 'relative' }}>
                        <button className="btn btn-ghost btn-icon btn-sm" onClick={() => setOpenMenu(openMenu === id ? null : id)}><MoreHorizontal size={16} /></button>
                        {openMenu === id && (
                          <div style={{ position: 'absolute', right: 0, top: '110%', zIndex: 100, background: 'var(--bg-surface)', border: '1px solid var(--border)', borderRadius: 'var(--radius-md)', padding: 6, minWidth: 140, boxShadow: 'var(--shadow-lg)' }}>
                            {[
                              { label: 'View Details', icon: Eye,   onClick: () => { setViewModal(emp); setOpenMenu(null); } },
                              { label: 'Edit',          icon: Edit2, onClick: () => openEdit(emp) },
                              { label: 'Terminate',     icon: UserX, onClick: () => { setDeleteModal(emp); setOpenMenu(null); }, danger: true },
                            ].map(({ label, icon: Icon, onClick, danger }) => (
                              <button key={label} onClick={onClick} style={{ display: 'flex', alignItems: 'center', gap: 8, width: '100%', padding: '8px 10px', background: 'none', border: 'none', cursor: 'pointer', borderRadius: 'var(--radius-sm)', fontSize: '0.83rem', color: danger ? 'var(--red)' : 'var(--text-secondary)' }} onMouseEnter={e => e.currentTarget.style.background = 'var(--bg-elevated)'} onMouseLeave={e => e.currentTarget.style.background = 'none'}>
                                <Icon size={14} /> {label}
                              </button>
                            ))}
                          </div>
                        )}
                      </td>
                    </tr>
                  );
                })}
              </tbody>
            </table>
          </div>
        </>
      )}

      <Modal open={createModal} onClose={() => setCreateModal(false)} title="Add New Employee" size="modal-lg" footer={<><button className="btn btn-secondary" onClick={() => setCreateModal(false)}>Cancel</button><button className="btn btn-primary" onClick={handleCreate} disabled={saving}>{saving ? <InlineSpinner /> : 'Create Employee'}</button></>}>
        <EmployeeForm data={formData} onChange={(k, v) => { setFormData(f => ({ ...f, [k]: v })); setFormErrors(e => ({ ...e, [k]: '' })); }} departments={departments} positions={positions} locations={locations} supervisors={supervisors} errors={formErrors} isCreate={true} />
      </Modal>

      <Modal open={!!editModal} onClose={() => setEditModal(null)} title="Edit Employee" size="modal-lg" footer={<><button className="btn btn-secondary" onClick={() => setEditModal(null)}>Cancel</button><button className="btn btn-primary" onClick={handleUpdate} disabled={saving}>{saving ? <InlineSpinner /> : 'Save Changes'}</button></>}>
        <EmployeeForm data={formData} onChange={(k, v) => { setFormData(f => ({ ...f, [k]: v })); setFormErrors(e => ({ ...e, [k]: '' })); }} departments={departments} positions={positions} locations={locations} supervisors={supervisors} errors={formErrors} />
      </Modal>

      <Modal open={!!viewModal} onClose={() => setViewModal(null)} title="Employee Details" size="modal-lg">
        {viewModal && (
          <div>
            <div style={{ display: 'flex', gap: 16, alignItems: 'center', marginBottom: 20 }}>
              <div className="avatar" style={{ width: 64, height: 64, fontSize: '1.5rem', borderRadius: 12 }}>{(`${viewModal.FirstName || '?'}`)[0].toUpperCase()}</div>
              <div><div style={{ fontSize: '1.1rem', fontWeight: 700 }}>{viewModal.FullName || `${viewModal.FirstName} ${viewModal.LastName}`}</div><div style={{ color: 'var(--text-secondary)', fontSize: '0.85rem' }}>{viewModal.Email}</div></div>
            </div>
            {[
              { label: 'Phone',         value: viewModal.Phone },
              { label: 'Department',    value: deptName(viewModal.DepartmentID) },
              { label: 'Position',      value: posName(viewModal.PositionID) },
              { label: 'Hire Date',     value: viewModal.StartDate ? new Date(viewModal.StartDate).toLocaleDateString() : '—' },
            ].map(({ label, value }) => <div className="info-row" key={label}><span className="info-row-label">{label}</span><span className="info-row-value">{value || '—'}</span></div>)}
          </div>
        )}
      </Modal>

      <PositionsManager open={positionsModal} onClose={() => setPositionsModal(false)} positions={positions} onRefresh={() => employeeAPI.getPositions().then(res => setPositions(res.data?.data?.positions || []))} />
      <CredentialsDialog data={credentialsDialog} onClose={() => setCredentialsDialog(null)} />
      <ConfirmDialog open={!!deleteModal} onClose={() => setDeleteModal(null)} onConfirm={handleDelete} loading={deleting} title="Terminate Employee" message={`Terminate this employee?`} variant="danger" />
    </>
  );
}
